{
  "verses": [
    {
      "n": 1,
      "column": "left",
      "text": "Eena Dseefina no Af-\nfawa (Dfeedama).\n"
    },
    {
      "n": 2,
      "column": "left",
      "text": "Ak Deews! ne\nzeeti kluſſu/ un ne eſti ta ka\nkuris/ un ne aisturrajs ak\nSTIPRAJS DEEWS!\n"
    },
    {
      "n": 3,
      "column": "left",
      "text": "Jo rangi/ tawi Eenaidnee.\nki trakko/ un tawi Nihdetaji pa-\nzelf to Galonu.\n"
    },
    {
      "n": 4,
      "column": "left",
      "text": "Tee xenmahs wiliqns\nPadehmus prett taweem Kan-\ndim/ un farunnajahs prett ta-\nweem Apflehpteem.\n"
    },
    {
      "n": 5,
      "column": "left",
      "text": "Tee faftata: Nahzeet /is-\ndeldeftni tohs/ ka tee wairs par\nTantu ue paleek/ un ka tas I-\nfraëta Wahrs wairs ne tohp\npeeminnehts.\n"
    },
    {
      "n": 6,
      "column": "left",
      "text": "Jo tee irr no Sirds koḫ-\npa farunnajuschees / un weenu\nDerribu pretti tew darrijschi.\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Gedoma un to Ismaëli-\nteu Teltis/ Moabs un tee Aga-\nritezi.\n"
    },
    {
      "n": 8,
      "column": "left",
      "text": "Gebals / Ammons un A-\nmalesks/ tee Wilifteci ar Tirus\nEedsihwotajeem.\n"
    },
    {
      "n": 9,
      "column": "left",
      "text": "Ir Affurs winneem klaht\nstahw/ un itr teem Behrneem Lat\npar Elkoni/ Sela.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Darri teem / ka Midija-\nnam/ ka Sifferam / ka Jabi-\nnam pee tahs Uppes Kison.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Kas famaitati irr Endo-\nrâ/ un par Subdeem tappufschi\nwirs Semnes.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Darri tohs un winna\nceelas-kungns ta ka Orebu un\nu/un wiﬀus-winnu Wirfuee-\nfa Sebu un Zalmunu.\n"
    },
    {
      "n": 13,
      "column": "right",
      "text": "Kas fazztja : Nem-\ntahs skaftas Deewa Eh\nmums par Eemantofchanu.\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Mans Deews / da\ntohs ta ka Weejuli/ ka Ring\njus Wehja Preefscha.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Itt ka Ugguns weenu\nschu fadedsina/ un ka weena\nma tohs Kalnus eededsina.\n"
    },
    {
      "n": 16,
      "column": "right",
      "text": "Ta patt dsennees te\npakkat ar tawu Wehtru / un\ntruhzina tohs ar taweem\nkeem.\n"
    },
    {
      "n": 17,
      "column": "right",
      "text": "Bildi winnu Waiqns\nKaunu/ ka tee / ak KUNG\nTawu Wahrdn mekle.\n"
    },
    {
      "n": 18,
      "column": "right",
      "text": "Lai tee Kannā tohp /\nistruhzinajahs muhschigi mu\nscham/ un apkaunoti ktuhst/\nbohja eet.\n"
    },
    {
      "n": 19,
      "column": "right",
      "text": "Ka tee afsihst/ ka tu wee\npats ar tawu Wahrdn ehti\nKUNGS / tas Wiffu-angfi\nkajs pahr wiffu Pafauli.\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Eena Dseefina us\nGittit/preefsch ta au\nita Dseedataja/ sta\nteem Behrneem Korus.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Ka mthligas irr taw\nMa\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
